const raw = items[0]?.json || {};
const payload = raw.payload && typeof raw.payload === 'object' && !Array.isArray(raw.payload) ? raw.payload : raw;
const relativePath = payload.relative_path || payload.relativePath || raw.relative_path || raw.relativePath;
const content = payload.content || raw.content;
if (!relativePath) throw new Error('Missing relative_path / relativePath');
if (!content) throw new Error('Missing content');
return [{
  json: {
    meta: {
      workflow_name: 'Obsidian_Writeback',
      timestamp: new Date().toISOString(),
      trigger_source: raw.trigger_source || 'obsidian_writeback_webhook',
      risk_level: raw.risk_level || 'low'
    },
    context: {
      canonical_links: [
        '[[00-System/Obsidian-Knowledge-System|Obsidian Knowledge System]]'
      ],
      constraints: [
        'Write only markdown files inside the configured Obsidian root',
        'Do not let automation mutate files outside docs'
      ]
    },
    payload: {
      relative_path: String(relativePath),
      content: String(content),
      mode: String(payload.mode || raw.mode || 'create'),
      dry_run: Boolean(payload.dry_run ?? payload.dryRun ?? raw.dry_run ?? raw.dryRun ?? false)
    }
  }
}];

const item = items[0]?.json || {};
const required = ['agent', 'workflow', 'status', 'mode', 'relative_path', 'absolute_path', 'bytes_written', 'reason', 'next_step'];
for (const key of required) {
  if (!(key in item)) throw new Error(`Missing required key: ${key}`);
}
const allowedStatus = new Set(['done', 'partial', 'blocked', 'needs_review', 'queued']);
if (!allowedStatus.has(item.status)) throw new Error(`Invalid status: ${item.status}`);
const allowedModes = new Set(['create', 'append', 'replace']);
if (!allowedModes.has(item.mode)) throw new Error(`Invalid mode: ${item.mode}`);
item.execution_summary = item.status === 'done'
  ? `Writeback OK -> ${item.relative_path}`
  : `Writeback needs review -> ${item.reason}`;
return [{ json: item }];
